```javascript
const Discord = require('discord.js');
const bot = new Discord.Client({ intents: Discord.Intents.ALL });

const botToken = 'YOUR_BOT_TOKEN';

bot.on('ready', () => {
  console.log('Bot connected');
});

bot.on('message', async message => {
  if (message.author.bot) return;

  const prefix = '!';
  if (!message.content.startsWith(prefix)) return;

  const command = message.content.slice(prefix.length).split(' ')[0];
  const args = message.content.slice(prefix.length + command.length + 1).split(' ');

  switch (command.toLowerCase()) {
    case 'ban':
      if (!message.member.roles.find(role => role.name === 'Banned')) {
        await message.member.addRole('Banned');
        await message.channel.send(`Banned ${message.author.username} from ${message.channel.name}`);
      } else {
        await message.channel.send(`${message.author.username} is already banned from ${message.channel.name}`);
      }
      break;

    default:
      await message.channel.send(`Unknown command: ${command}`);
  }
});

bot.login(botToken);
```
