std::string convertMarkdownToHtml(const std::string_view markdownText) {
    // Load the markdown-it library
    markdownpp::MarkdownIt it(markdownpp::MarkdownIt::ENGINE_JAVASCRIPT);
    it.set_html_processor(new markdownpp::HtmlToPygmentsProcessor());

    // Add the markdown-it-pygments.min.js library
