Here's a JavaScript function that checks if any of the five numbers in the input array is a valid prime number, and then prints the number to the console:
```javascript
function isPrime(num) {
  if (num <= 1) {
    return false;
  }

  for (let i = 2; i < num; i++) {
    if (num % i === 0) {
      return false;
    }
  }

  return true;
}

function checkPrimeNumbers(arr) {
  for (let i = 0; i < arr.length; i++) {
    if (isPrime(arr[i])) {
      console.log(arr[i]);
    }
  }
}

const inputArray = [1, 2, 3, 4, 5];
checkPrimeNumbers(inputArray);
```
